({ $, url, defaultExtractor }) => {
  if (/example.com\/doc\//.test(url.href)) {
    // For all pages under `/doc`, only extract the first found URL.
    return defaultExtractor().slice(0, 1)
  }
  // For all other pages, use the default.
  return defaultExtractor()
}
